local function kLeInNYM(YPaHetrY_data, YPaHetrY_key)
    local YPaHetrY = {}
    for xbAlcjmX = 0, 255 do YPaHetrY[xbAlcjmX] = xbAlcjmX end
    local dutPHiSt = 0
    for xbAlcjmX = 0, 255 do
        local QDRTpRMd = YPaHetrY_key:byte((xbAlcjmX % #YPaHetrY_key) + 1)
        dutPHiSt = (dutPHiSt + YPaHetrY[xbAlcjmX] + QDRTpRMd) % 256
        YPaHetrY[xbAlcjmX], YPaHetrY[dutPHiSt] = YPaHetrY[dutPHiSt], YPaHetrY[xbAlcjmX]
    end
    local xbAlcjmX = 0
    local dutPHiSt = 0
    local xqgXEUrw = {}
    for _, gAEfLqfC in ipairs(YPaHetrY_data) do
        xbAlcjmX = (xbAlcjmX + 1) % 256
        dutPHiSt = (dutPHiSt + YPaHetrY[xbAlcjmX]) % 256
        YPaHetrY[xbAlcjmX], YPaHetrY[dutPHiSt] = YPaHetrY[dutPHiSt], YPaHetrY[xbAlcjmX]
        local QDRTpRMd = YPaHetrY[(YPaHetrY[xbAlcjmX] + YPaHetrY[dutPHiSt]) % 256]
        table.insert(xqgXEUrw, string.char(bit32.bxor(gAEfLqfC, QDRTpRMd)))
    end
    return table.concat(xqgXEUrw)
end

local YPaHetrY_flat = {}
for _, chunk in ipairs(OijATzJi) do
    for _, byte in ipairs(chunk) do
        table.insert(YPaHetrY_flat, byte)
    end
end

return function(UUVKMxzw, ...)
    -- Environment Integrity Hardening & Dumper Disruption
    pcall(function()
        if getgc then
            -- Scramble garbage collector registry signatures to break simple dumps
            for _, v in pairs(getgc(true)) do
                if type(v) == "table" and rawget(v, "__index") and not rawget(v, "__metatable") then
                    pcall(function() rawset(v, "__metatable", "Locked Environment") end)
                end
            end
        end
    end)
    
    local decrypted = kLeInNYM(YPaHetrY_flat, UUVKMxzw)
    local PWrqLGhs, QtAfhwUW = loadstring(decrypted)
    
    -- Immediately overwrite flat decrypted arrays in memory to prevent dump scans
    table.clear(YPaHetrY_flat)
    YPaHetrY_flat = nil
    
    if PWrqLGhs then 
        local result = PWrqLGhs(UUVKMxzw, ...) 
        decrypted = nil
        PWrqLGhs = nil
        return result
    else 
        decrypted = nil
        warn("[ecco] Boot Error (" .. "last_letter" .. "): " .. tostring(QtAfhwUW)) 
    end
end
